const b = $json.body || {};
const key = String(b.r2_key || "");
const base = key.split("/").pop() || "";
const m = base.match(/^([a-z]+)-(\d+)-/);
const role = m ? m[1] : "";
const ord = m ? parseInt(m[2], 10) : 0;
const sid = String(b.submission_id || "");
const byteSize = typeof b.byte_size === "number" ? b.byte_size : parseInt(b.byte_size, 10) || 0;
const valid =
  /^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$/.test(sid) &&
  key.length > 0 &&
  ["front", "back", "tag", "flaw"].includes(role) &&
  ord >= 1 && ord <= 6 &&
  byteSize > 0;
return [{ json: { payload: {
  submission_id: sid,
  r2_key: key,
  role,
  ord,
  content_type: b.content_type || "image/jpeg",
  byte_size: byteSize,
  width: b.width == null ? null : b.width,
  height: b.height == null ? null : b.height,
  client_stripped_exif: !!b.client_stripped_exif,
  valid,
} } }];

const r = $json || {};
if (!r.valid) return [{ json: { statusCode: 400, body: { ok: false, error: "bad_photo" } } }];
return [{ json: { statusCode: 200, body: { ok: true, photo_id: r.photo_id || null } } }];

const crypto = require('crypto');
const secret = $env.INTAKE_WEBHOOK_SECRET || '';
const item = ($input.first() && $input.first().json) || {};
const h = item.headers || {};
const sig = String(h['x-ttr-signature'] || '');
const ts = String(h['x-ttr-timestamp'] || '');
const body = item.body;
// Reproduce exactly what the Pages function signed: JSON.stringify(payload).
// n8n parses the JSON body into an object preserving key order, so re-stringify
// is byte-identical for compact JSON. If a string slipped through, sign as-is.
const raw = (typeof body === 'string') ? body : JSON.stringify(body == null ? {} : body);
let ok = false;
if (secret && sig && /^[0-9]+$/.test(ts)) {
  const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(ts + '.' + raw).digest('hex');
  const a = Buffer.from(sig);
  const b = Buffer.from(expected);
  const fresh = Math.abs(Date.now() - Number(ts)) < 300000; // 5 min replay window
  ok = a.length === b.length && crypto.timingSafeEqual(a, b) && fresh;
}
if (!ok) { throw new Error('unauthorized'); }
return $input.all();
